from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and score statistics

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Handle edge case: empty input
    if not search_results:
        return {}

    # Initialize dictionary to accumulate grouped data
    grouped_data = defaultdict(list)

    # Iterate through each SearchResult and group by the specified metadata field
    for result in search_results:
        # Extract metadata value for grouping field, handle missing values
        group_value = result.metadata.get(group_by_field)
        if group_value is None:
            group_value = 'unknown'

        # Add result to the appropriate group
        grouped_data[group_value].append(result)

    # Prepare the final aggregated results dictionary
    aggregated_results = {}

    # Apply aggregation functions to compute final statistics for each group
    for group_value, results in grouped_data.items():
        if aggregation_funcs is None:
            # Use default statistics
            aggregated_stats = {}
            if results:
                # Calculate count
                aggregated_stats['count'] = len(results)

                # Calculate score statistics
                scores = [result.score for result in results]
                if scores:
                    aggregated_stats['avg_score'] = sum(scores) / len(scores)
                    aggregated_stats['max_score'] = max(scores)
                    aggregated_stats['min_score'] = min(scores)
            else:
                # Empty group
                aggregated_stats['count'] = 0

        else:
            # Use custom aggregation functions
            aggregated_stats = {}
            for field_name, agg_func in aggregation_funcs.items():
                # Extract field values from results
                field_values = []
                for result in results:
                    # Handle different field types: top-level fields and metadata fields
                    if field_name in ['id', 'score', 'text']:
                        field_values.append(getattr(result, field_name))
                    elif field_name == 'metadata':
                        field_values.append(result.metadata)
                    else:
                        # Check both top-level and metadata
                        field_value = getattr(result, field_name, None)
                        if field_value is None:
                            # Try metadata if not found at top level
                            field_value = result.metadata.get(field_name)
                        field_values.append(field_value)

                # Apply aggregation function, handle potential errors
                try:
                    if field_values:
                        aggregated_stats[field_name] = agg_func(field_values)
                    else:
                        aggregated_stats[field_name] = None
                except Exception:
                    aggregated_stats[field_name] = None

        aggregated_results[group_value] = aggregated_stats

    return aggregated_results

